import{_ as l,H as t,f as a,i as e}from"./chunks/framework.Cvt1eIE0.js";const o="/quote/images/tired_price/index.png",r="/quote/images/tired_price/select1.png",n="/quote/images/tired_price/select2.png",s="/quote/images/quote_limit/qty.png",u="/quote/images/quote_limit/total.png",p="/quote/images/quote_limit/upload.png",f=JSON.parse('{"title":"定价与规则策略","description":"","frontmatter":{},"headers":[],"relativePath":"quote/pricing-rules.md","filePath":"quote/pricing-rules.md"}'),c={name:"quote/pricing-rules.md"};function d(h,i,m,q,_,g){return t(),a("div",null,[...i[0]||(i[0]=[e('<h1 id="定价与规则策略" tabindex="-1">定价与规则策略 <a class="header-anchor" href="#定价与规则策略" aria-label="Permalink to &quot;定价与规则策略&quot;">​</a></h1><p>Quote App 提供了灵活的定价引擎，帮助您针对不同客户和订单规模实施差异化价格策略。</p><h2 id="_1-阶梯定价-tiered-pricing" tabindex="-1">1. 阶梯定价 (Tiered Pricing) <a class="header-anchor" href="#_1-阶梯定价-tiered-pricing" aria-label="Permalink to &quot;1. 阶梯定价 (Tiered Pricing)&quot;">​</a></h2><p>阶梯定价允许您根据购买数量自动调整单价。</p><h3 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h3><ol><li><p>进入 <strong>定价规则 (Pricing)</strong> -&gt; <strong>阶梯定价</strong>。 <img src="'+o+'" alt="tired_price"></p></li><li><p>选择适用的产品或分类。 <img src="'+r+'" alt="select1"></p></li></ol><p><img src="'+n+'" alt="select2"></p><ol start="3"><li><p>设置区间，例如：</p><ul><li>1-10 件：$10.00</li><li>11-50 件：$9.00</li><li>50 件以上：$8.00</li></ul></li><li><p>保存后，当报价单中的产品数量达到对应区间时，系统将自动应用价格。</p></li></ol><h2 id="_2-最小起订量-moq" tabindex="-1">2. 最小起订量 (MOQ) <a class="header-anchor" href="#_2-最小起订量-moq" aria-label="Permalink to &quot;2. 最小起订量 (MOQ)&quot;">​</a></h2><p>除了阶梯定价外，Quote App 还支持对报价数量与报价金额设置提交门槛，避免客户提交不符合批发条件的询价单。</p><h3 id="配置入口" tabindex="-1">配置入口 <a class="header-anchor" href="#配置入口" aria-label="Permalink to &quot;配置入口&quot;">​</a></h3><p>进入 <strong>Settings -&gt; Quote Limits</strong>，可以看到数量与金额限制相关设置。</p><h3 id="功能说明" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明" aria-label="Permalink to &quot;功能说明&quot;">​</a></h3><h4 id="_1-数量限制-qty-limit" tabindex="-1">1. 数量限制 (Qty limit) <a class="header-anchor" href="#_1-数量限制-qty-limit" aria-label="Permalink to &quot;1. 数量限制 (Qty limit)&quot;">​</a></h4><p>您可以开启 <strong>Set quote quantity limit</strong>，并选择限制方式：</p><p><img src="'+s+'" alt="quote_limit"></p><ul><li><strong>By product</strong>：按同一产品下所有变体合并后的总数量进行限制。</li><li><strong>By product variants</strong>：按每一个变体各自的数量进行限制。</li></ul><p>这两个选项的区别如下：</p><h5 id="by-product" tabindex="-1">By product <a class="header-anchor" href="#by-product" aria-label="Permalink to &quot;By product&quot;">​</a></h5><p>系统会把同一个产品下不同变体的数量先加总，再判断是否满足最小值或最大值。</p><p>例如：</p><ul><li>产品 A 有 3 个变体：红色、蓝色、黑色</li><li>客户提交红色 2 件、蓝色 3 件、黑色 1 件</li></ul><p>如果您选择 <strong>By product</strong>，系统会这样计算：</p><ul><li>产品 A 总数量 = 2 + 3 + 1 = 6</li></ul><p>也就是说，系统判断的是“这个产品整体买了多少”，而不是分别判断红色、蓝色、黑色是否单独达标。</p><p>适用场景：</p><ul><li>您关心的是同一个产品系列的总采购量</li><li>客户可以通过不同颜色、尺寸或规格组合凑够 MOQ</li><li>只要同一产品总数量达到门槛，就允许提交报价</li></ul><h5 id="by-product-variants" tabindex="-1">By product variants <a class="header-anchor" href="#by-product-variants" aria-label="Permalink to &quot;By product variants&quot;">​</a></h5><p>系统会对每一个变体单独检查数量，不会把不同变体的数量合并。</p><p>例如：</p><ul><li>产品 A 有 2 个变体：红色、蓝色</li><li>客户提交红色 2 件、蓝色 3 件</li></ul><p>如果您选择 <strong>By product variants</strong>，系统会分别判断：</p><ul><li>红色变体是否达到限制</li><li>蓝色变体是否达到限制</li></ul><p>即使红色和蓝色加起来已经达到总数量门槛，只要其中某一个变体本身没有达到最低数量，系统仍然会阻止提交。</p><p>适用场景：</p><ul><li>每个变体都需要独立满足 MOQ</li><li>不允许客户通过混搭不同变体来凑够最低数量</li><li>不同颜色、尺寸或规格在生产、采购、包装上是独立单位</li></ul><h5 id="如何选择" tabindex="-1">如何选择 <a class="header-anchor" href="#如何选择" aria-label="Permalink to &quot;如何选择&quot;">​</a></h5><ul><li>如果您的规则是“同一个产品总共买够多少就可以”，请选择 <strong>By product</strong></li><li>如果您的规则是“每个变体都必须单独买够多少”，请选择 <strong>By product variants</strong></li></ul><p>系统会在客户提交报价前进行校验：</p><ul><li>当数量低于最低门槛时，前台会提示并阻止提交。</li><li>当数量超过最高门槛时，前台也会提示并阻止提交。</li></ul><h4 id="_2-最小报价小计限制-subtotal-limit" tabindex="-1">2. 最小报价小计限制 (Subtotal limit) <a class="header-anchor" href="#_2-最小报价小计限制-subtotal-limit" aria-label="Permalink to &quot;2. 最小报价小计限制 (Subtotal limit)&quot;">​</a></h4><p>您还可以开启 <strong>Enable quote subtotal limit</strong>，设置一笔报价单必须达到的最低金额。</p><p><img src="'+u+'" alt="quote_limit"></p><ul><li>当客户当前报价商品的小计低于您设置的金额时，系统会阻止提交。</li><li>这项规则适合用于控制最低采购金额，而不只是控制件数。</li></ul><h4 id="_3-产品-变体覆盖默认规则" tabindex="-1">3. 产品 / 变体覆盖默认规则 <a class="header-anchor" href="#_3-产品-变体覆盖默认规则" aria-label="Permalink to &quot;3. 产品 / 变体覆盖默认规则&quot;">​</a></h4><p>MOQ 支持“全局默认值 + 产品或变体覆盖值”的方式：</p><ul><li>您可以在设置里先定义店铺默认数量限制。</li><li>如果某些产品或变体有特殊要求，可以通过对应的 metafield 覆盖默认值。</li><li>当产品或变体存在单独设置时，系统会优先使用该产品或变体的限制。</li></ul><h3 id="批量修改产品-moq" tabindex="-1">批量修改产品 MOQ <a class="header-anchor" href="#批量修改产品-moq" aria-label="Permalink to &quot;批量修改产品 MOQ&quot;">​</a></h3><p>如果您需要一次更新多个产品或多个变体的起订量，可以使用 <strong>Bulk import variant minimums (CSV)</strong>。</p><p><img src="'+p+'" alt="quote_limit"></p><h4 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h4><ol><li>点击 <strong>Download Sample CSV</strong> 下载模板。</li><li>按模板填写需要更新的变体资料。</li></ol><h4 id="csv-支持的字段" tabindex="-1">CSV 支持的字段 <a class="header-anchor" href="#csv-支持的字段" aria-label="Permalink to &quot;CSV 支持的字段&quot;">​</a></h4><ul><li><code>variant_id</code>：Shopify 变体 ID</li><li><code>sku</code>：变体 SKU</li><li><code>product_title</code>：产品名称，仅作辅助参考</li><li><code>min_quote_qty</code>：该变体的最低报价数量</li><li><code>max_quote_qty</code>：该变体的最高报价数量</li></ul><p>说明：</p><ul><li><code>variant_id</code> 或 <code>sku</code> 至少需要提供一个，用于定位具体变体。</li><li>适合批量维护不同产品或变体的 MOQ。</li><li>导入后会直接更新对应变体的数量限制设置。</li></ul><h3 id="前台效果" tabindex="-1">前台效果 <a class="header-anchor" href="#前台效果" aria-label="Permalink to &quot;前台效果&quot;">​</a></h3><p>当客户在 storefront 提交报价时，系统会自动检查：</p><ul><li>变体数量是否满足最小/最大限制</li><li>产品总数量是否满足限制</li><li>报价小计是否达到最低金额</li></ul><p>只要任一条件不符合，系统就会提示错误并阻止提交，确保收到的报价都符合您的业务规则。</p><hr><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>阶梯定价与 MOQ 规则会同时生效，请确保您的定价逻辑不会产生冲突。</li><li>如果同时设置了默认值和产品/变体级覆盖值，系统会优先采用更具体的产品或变体设置。</li><li>批量导入前建议先下载模板，避免字段名称或格式错误导致导入失败。</li></ul>',63)])])}const P=l(c,[["render",d]]);export{f as __pageData,P as default};
